primeCheck:
# Function to check if a number is prime
function Test-Prime {
    param(
        [Parameter(Mandatory=$true)]
        [int]$Number
    )

    if ($Number -le 1) {
        return $false # Numbers <= 1 are not prime
    }
    if ($Number -le 3) {
        return $true # 2 and 3 are prime
    }
    if ($Number % 2 -eq 0 -or $Number % 3 -eq 0) {
        return $false # Divisible by 2 or 3
    }

    # Check factors from 5 upwards, stepping by 6
    $i = 5
    # Calculate integer square root
    $limit = [int][math]::Sqrt($Number)

    while ($i -le $limit) {
        if ($Number % $i -eq 0 -or $Number % ($i + 2) -eq 0) {
            return $false # Divisor found
        }
        $i += 6
    }

    return $true # No divisors found, it's prime
}

# Example usage
$numbersToCheck = 2, 3, 4, 17, 25, 29, 97, 100, 1, -5

foreach ($n in $numbersToCheck) {
    if (Test-Prime -Number $n) {
        Write-Host "$n is prime."
    } else {
        Write-Host "$n is not prime."
    }
}

readFile:
# Specify the path to the file
$filePath = ".\powershell_read_test.txt" # Assumes file in current directory

# Create a dummy file for reading
@"
Line 1 content from PowerShell.
This is the second line.
End of file line.
"@ | Set-Content -Path $filePath -Encoding UTF8
Write-Host "Created dummy file '$filePath' for reading."

Write-Host "--- Reading file '$filePath' using Get-Content ---"

if (Test-Path -Path $filePath -PathType Leaf) {
    try {
        # Get-Content reads the file line by line, returns an array of strings
        $fileContent = Get-Content -Path $filePath -Encoding UTF8 -ErrorAction Stop
        Write-Host "File content (as array):"
        $fileContent # Output the array (each element prints on a new line)

        Write-Host "--- Processing line by line ---"
        foreach ($line in $fileContent) {
            Write-Host "Read line: $line"
        }

        # To get raw content as a single string:
        $rawContent = Get-Content -Path $filePath -Raw -Encoding UTF8
        # Write-Host "Raw content: $rawContent"

    } catch {
        Write-Error "Error reading file '$filePath': $($_.Exception.Message)"
    }
} else {
    Write-Warning "File not found or is a directory: '$filePath'"
}

# Clean up dummy file
Remove-Item -Path $filePath -Force
Write-Host "Cleaned up dummy file '$filePath'."

writeFile:
$filePath = ".\output_powershell.txt"
$content1 = "First line written by PowerShell."
$content2 = "Second line, also written."
$contentToAppend = "This line was appended."

# --- Write using Set-Content (overwrites or creates) ---
Write-Host "--- Writing to '$filePath' using Set-Content (overwrite) ---"
try {
    # Input can be a string or array of strings (each becomes a line)
    $linesToWrite = @(
        $content1,
        $content2
    )
    $linesToWrite | Set-Content -Path $filePath -Encoding UTF8 -ErrorAction Stop
    Write-Host "Successfully wrote initial content."
} catch {
     Write-Error "Error writing to '$filePath': $($_.Exception.Message)"
}

# --- Append using Add-Content (adds to end or creates) ---
Write-Host "--- Appending to '$filePath' using Add-Content ---"
try {
    $contentToAppend | Add-Content -Path $filePath -Encoding UTF8 -ErrorAction Stop
    Write-Host "Successfully appended content."
} catch {
     Write-Error "Error appending to '$filePath': $($_.Exception.Message)"
}

# --- Display final content ---
Write-Host "--- Final content of '$filePath': ---"
if (Test-Path -Path $filePath -PathType Leaf) {
    Get-Content -Path $filePath
} else {
    Write-Warning "File '$filePath' not found."
}

# Optional: Clean up
# Remove-Item -Path $filePath -Force

maxInArray:
$myArray = 10, 5, 42, 17, 8, 99, 32, -5, 0
Write-Host "Array: $($myArray -join ', ')"

# Use Measure-Object cmdlet with the -Maximum switch
$measurement = $myArray | Measure-Object -Maximum
$maxValue = $measurement.Maximum

Write-Host "Maximum value: $maxValue"

# Example with empty array
$emptyArray = @()
$measurementEmpty = $emptyArray | Measure-Object -Maximum
# $measurementEmpty.Maximum will be null or empty if array is empty
if ($measurementEmpty.Count -eq 0) {
    Write-Host "Cannot find maximum in an empty array."
} else {
    Write-Host "Maximum (empty array): $($measurementEmpty.Maximum)" # Should not print if logic is right
}

# Example with potentially non-numeric data (Measure-Object might error)
$mixedArray = 10, "apple", 30
try {
    $measurementMixed = $mixedArray | Measure-Object -Maximum -ErrorAction Stop
    Write-Host "Maximum (mixed array): $($measurementMixed.Maximum)"
} catch {
    Write-Error "Error finding maximum in mixed array: $($_.Exception.Message)"
}
